class Solution:
    def connect(self, root: 'Node') -> 'Node':
        node = root
        dummy = Node(0)
        tail = dummy
        while node:
            if node.left:
                tail.next = node.left
                tail = tail.next
            if node.right:
                tail.next = node.right
                tail = tail.next
            node = node.next
            if not node:
                node = dummy.next
                dummy.next = None
                tail = dummy
        return root

