var connect = function(root) {
    let node = root;
    const dummy = new Node(0);
    let tail = dummy;
    while (node) {
        if (node.left) {
            tail.next = node.left;
            tail = tail.next;
        }
        if (node.right) {
            tail.next = node.right;
            tail = tail.next;
        }
        node = node.next;
        if (!node) {
            node = dummy.next;
            dummy.next = null;
            tail = dummy;
        }
    }
    return root;
};
